(()=>{"use strict";document.addEventListener("DOMContentLoaded",()=>{!async function(){const t=Array.from(document.querySelectorAll('[id^="fragment-"]'));for(const e of t){const t=`fragments/${e.id.replace("fragment-","")}.html`;try{const r=await fetch(t);if(!r.ok)throw new Error(`HTTP error! status: ${r.status}`);const o=await r.text();e.innerHTML=o}catch(e){console.error(`Failed to load fragment ${t}:`,e)}}}()})})();